/**
 * Named release gate: ledger MCP coverage + mutation↔theorem map.
 * Primary: invoke from Aeon Forge / ForgoCD before fold-gated deploys.
 * Backup: optional GitHub Actions job mirroring this script.
 *
 * Config map (for humans / future automation): ../config/mechanization-release-map.json
 */
import { spawnSync } from 'node:child_process';
import { stderr } from 'node:process';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const gnosisRoot = join(dirname(fileURLToPath(import.meta.url)), '..');

function runStep(label: string, args: string[]): void {
  stderr.write(`[mechanization-release-gate] ${label}\n`);
  const result = spawnSync(args[0]!, args.slice(1), {
    cwd: gnosisRoot,
    stdio: 'inherit',
    env: process.env,
    shell: false,
  });
  if (result.status !== 0) {
    process.exit(result.status ?? 1);
  }
}

runStep('validate:ledger-mcp', ['pnpm', 'run', 'validate:ledger-mcp']);
runStep('validate:mutation-theorem-map', [
  'pnpm',
  'run',
  'validate:mutation-theorem-map',
]);

stderr.write('[mechanization-release-gate] ok\n');
